cargo loco generate scaffold casualty_card_treatment \
    casualty_card:references \
    oxygen_therapy_device:text! \
    oxygen_therapy_flow_rate:text! \
    tetanus_prophylaxis:text! \
    --htmx

cargo loco generate scaffold casualty_card_assessment_plan \
    casualty_card:references \
    working_diagnosis:text! \
    differential_diagnoses:text! \
    clinical_impression:text! \
    risk_stratification:text! \
