cargo loco generate scaffold casualty_card_disposition \
    casualty_card:references \
    disposition:text! \
    admitting_specialty:text! \
    admitting_consultant:text! \
    ward:text! \
    level_of_care:text! \
    discharge_diagnosis:text! \
    discharge_medications:text! \
    discharge_instructions:text! \
    follow_up:text! \
    return_precautions:text! \
    receiving_hospital:text! \
    reason_for_transfer:text! \
    mode_of_transfer:text! \
