cargo loco generate scaffold news2_result \
    casualty_card:references \
    total_score:int! \
    clinical_response:text! \
    has_any_single_score_3:bool! \
    parameter_scores:jsonb! \
    scored_at:ts! \
    --htmx

cargo loco generate scaffold flagged_issue \
    news2_result:references \
    flag_id:text! \
    category:text! \
    message:text! \
    priority:text! \
    --htmx

echo "Done."
